SELECT Item.[Season Code], Item.[Trademark Code], Item.[Budget Type], Item.[Collection Code], Item.[Line Code], Item_1.No_, ListinoVenditaWholesale.[Sales Code] AS ListinoWholesale, Avg(IIf(IsNull([ListinoVenditaWholesale].[Item NO_])=False,[ListinoVenditaWholesale.Listino],0)) AS PrezzoWholesale, ListinoVenditaRetail.[Sales Code] AS ListinoRetail, Avg(IIf(IsNull([ListinoVenditaRetail].[Item NO_])=False,[ListinoVenditaRetail.Listino],0)) AS PrezzoRetail, Item_1.Description, Item_1.[Description 2], Item.[Description 6], Item.[Variable Code 01] AS ColorCode, [Variable Code].Description AS ColorDescription, Item.[Variable Code 02] AS [Size], [NavisionEan-step0].[Cross-Reference No_] AS EAN, UPCCodes.[Cross-Reference No_] AS UPC, Item.[Carry Over], Item.[Future Carry Over], Item.Smu, Item.[Location Code], Item.[Delivery Period], Item.[Season Typology], Item.[Product Family], Item.[Product Sex], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], Item.[Tariff No_], Val([Item.Unit Volume]) AS UnitVolume, Val([Item.Gross Weight]) AS [GrossWeight(g)], Val([Item.Net Weight]) AS [NetWeight(g)], Val([Item.Height]) AS [Height(cm)], Val([Item.Width]) AS [Width(cm)], Val([Item.Depth]) AS [Depth(cm)], Val([Item.Standard Cost]) AS StandardCost, Item.[Country_Region of Origin Code], Item.[Vendor No_], Vendor.Name, Item.Manufacturer AS ManufacturerCode, Vendor_1.Name AS ManufacturerName, Item.[Potential Sold Out], Item.[Sold Out], Item.[Sold Out Date], Item.[Commission Group Code], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Upper Composition], Item.[Lining Composition], Item.[Outsole Composition], Item.[Insole Composition], Item.[Advertising Material]
FROM (((((((Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) INNER JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) LEFT JOIN ListinoVenditaWholesale ON Item.No_ = ListinoVenditaWholesale.[Item No_]) LEFT JOIN ListinoVenditaRetail ON Item.No_ = ListinoVenditaRetail.[Item No_]) LEFT JOIN UPCCodes ON Item.No_ = UPCCodes.[Item No_]) LEFT JOIN [NavisionEan-step0] ON Item.No_ = [NavisionEan-step0].[Item No_]) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
GROUP BY Item.[Season Code], Item.[Trademark Code], Item.[Budget Type], Item.[Collection Code], Item.[Line Code], Item_1.No_, ListinoVenditaWholesale.[Sales Code], ListinoVenditaRetail.[Sales Code], Item_1.Description, Item_1.[Description 2], Item.[Description 6], Item.[Variable Code 01], [Variable Code].Description, Item.[Variable Code 02], [NavisionEan-step0].[Cross-Reference No_], UPCCodes.[Cross-Reference No_], Item.[Carry Over], Item.[Future Carry Over], Item.Smu, Item.[Location Code], Item.[Delivery Period], Item.[Season Typology], Item.[Product Family], Item.[Product Sex], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], Item.[Tariff No_], Val([Item.Unit Volume]), Val([Item.Gross Weight]), Val([Item.Net Weight]), Val([Item.Height]), Val([Item.Width]), Val([Item.Depth]), Val([Item.Standard Cost]), Item.[Country_Region of Origin Code], Item.[Vendor No_], Vendor.Name, Item.Manufacturer, Vendor_1.Name, Item.[Potential Sold Out], Item.[Sold Out], Item.[Sold Out Date], Item.[Commission Group Code], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Upper Composition], Item.[Lining Composition], Item.[Outsole Composition], Item.[Insole Composition], Item.[Advertising Material], Item.[Configurator Relation]
HAVING (((Item.[Season Code])=[forms]![principale]![FiltroStagioneEAN]) AND ((Item.[Configurator Relation])=3))
ORDER BY Item.[Trademark Code], Item.[Collection Code], Item.[Line Code], Item_1.No_, Item.[Variable Code 01], Item.[Variable Code 02];

